import os
import requests
import time
from typing import List
from dotenv import load_dotenv

load_dotenv()

def realizar_peticiones(ids: List[int], jwt_token: str, delay: float = 0.5):
    """
    Realiza peticiones a la API con diferentes IDs
    
    Args:
        ids: Lista de IDs enteros
        jwt_token: Token JWT para autenticación
        delay: Tiempo de espera entre peticiones (en segundos)
    """
    
    # URL base (sin el ID final)
    base_url = "https://renhacemos.direccionsustitucion.gov.co/api/2.0/validacion/item-persona/completar"
    
    # Headers con el token JWT
    headers = {
        "Authorization": f"Bearer {jwt_token}",
        "Content-Type": "application/json",
        "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36"
    }
    
    resultados = []
    
    for i, id_num in enumerate(ids, 1):
        try:
            # Construir URL completa
            url = f"{base_url}/{id_num}/"
            
            print(f"[{i}/{len(ids)}] Procesando ID: {id_num}")
            
            # Realizar la petición GET
            response = requests.get(url, headers=headers, timeout=30)
            
            # Registrar resultado
            resultado = {
                "id": id_num,
                "status_code": response.status_code,
                "success": response.status_code == 200,
                "response": response.text if response.status_code != 200 else None
            }
            
            if response.status_code == 200:
                print(f"  ✓ Éxito - Status: {response.status_code}")
                # Si necesitas procesar la respuesta exitosa, puedes hacerlo aquí
                # data = response.json()
            else:
                print(f"  ✗ Error - Status: {response.status_code}")
                print(f"    Respuesta: {response.text[:200]}...")
            
            resultados.append(resultado)
            
            # Esperar antes de la siguiente petición (para no saturar el servidor)
            if i < len(ids):
                time.sleep(delay)
                
        except requests.exceptions.RequestException as e:
            print(f"  ✗ Error de conexión para ID {id_num}: {str(e)}")
            resultados.append({
                "id": id_num,
                "status_code": None,
                "success": False,
                "error": str(e)
            })
        except Exception as e:
            print(f"  ✗ Error inesperado para ID {id_num}: {str(e)}")
            resultados.append({
                "id": id_num,
                "status_code": None,
                "success": False,
                "error": str(e)
            })
    
    return resultados

